from itertools import islice
from heapq import heappop, heappush
from sympy import factorint, isprime, nextprime, primefactors
def A386527_gen(): # generator of terms
    def is_squarefree(n): return max(factorint(n).values(),default=1)<=1
    h, hset = [1], {1}
    while True:
        m = heappop(h)
        if not (is_squarefree(m-1) or is_squarefree(m+1)):
            yield m
        ps = primefactors(m)
        ps.append(nextprime(max(ps,default=1)))
        for p in ps:
            mp = m*p
            if mp not in hset:
                heappush(h,mp)
                hset.add(mp)
A386527_list = list(islice(A386527_gen(),40)) # _Chai Wah Wu_, Mar 21 2026

